dslRule:
/*!id: jdt.internal.cleanup.varoccurrencevisitor.rename-type*/
/*!description: Renames internal JDT cleanup type VarOccurrenceVisitor to VarConflictVisitor.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
org.eclipse.jdt.internal.corext.dom.VarOccurrenceVisitor
=> org.eclipse.jdt.internal.corext.dom.VarConflictVisitor
;;

/*!id: jdt.internal.cleanup.varoccurrencevisitor.rename-constructor*/
/*!description: Updates constructor calls for internal JDT cleanup type from VarOccurrenceVisitor to VarConflictVisitor.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
new org.eclipse.jdt.internal.corext.dom.VarOccurrenceVisitor($allowedVars, true)
=> new org.eclipse.jdt.internal.corext.dom.VarConflictVisitor($allowedVars, true)
;;

/*!id: jdt.internal.cleanup.varoccurrencevisitor.rename-method*/
/*!description: Renames method call from isVarUsed() to isVarConflicting() on internal JDT cleanup visitor.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
$varOccurrenceVisitor.isVarUsed() :: instanceof($varOccurrenceVisitor, "org.eclipse.jdt.internal.corext.dom.VarOccurrenceVisitor")
=> $varOccurrenceVisitor.isVarConflicting()
;;

